1	<script lang="ts">
2		import { Loader2 } from 'lucide-svelte';
3		import { projectStore } from '$lib/stores/project.svelte';
4		import { nodeStore } from '$lib/stores/node.svelte';
5		import { createClient } from '$lib/gql/client';
6		import { gql } from 'graphql-request';
7	
8		// Persistent drain-queue worker indicator (ddx-b6cf025c). Shown on every
9		// route inside a selected project; hidden when no project is selected.
10		// Polls every 3s — lightweight, and avoids wiring a new subscription
11		// stream just for nav badge updates. AC requires ≤2s worker-state and
12		// ≤5s ready-count freshness; 3s poll sits inside both bounds.
13	
14		const SUMMARY_QUERY = gql`
15			query QueueAndWorkersSummary($projectId: String!) {
16				queueAndWorkersSummary(projectId: $projectId) {
17					readyBeads
18					runningWorkers
19					totalWorkers
20				}
21			}
22		`;
23	
24		let readyBeads = $state(0);
25		let runningWorkers = $state(0);
26		let loaded = $state(false);
27	
28		const projectId = $derived(projectStore.value?.id ?? null);
29		const nodeId = $derived(nodeStore.value?.id ?? null);
30		const workersHref = $derived(
31			nodeId && projectId ? `/nodes/${nodeId}/projects/${projectId}/workers` : null
32		);
33		const active = $derived(runningWorkers > 0);
34	
35		const label = $derived.by(() => {
36			if (!loaded) return '';
37			if (active) {
38				const w = runningWorkers === 1 ? 'worker' : 'workers';
39				return `${runningWorkers} ${w} · ${readyBeads} ready`;
40			}
41			return `Queue: ${readyBeads} ready`;
42		});
43	
44		async function refresh(pid: string) {
45			try {
46				const client = createClient(fetch);
47				const data = await client.request<{
48					queueAndWorkersSummary: {
49						readyBeads: number;
50						runningWorkers: number;
51						totalWorkers: number;
52					};
53				}>(SUMMARY_QUERY, { projectId: pid });
54				readyBeads = data.queueAndWorkersSummary.readyBeads;
55				runningWorkers = data.queueAndWorkersSummary.runningWorkers;
56				loaded = true;
57			} catch {
58				// Keep previous values on transient failure. AC #4: "falls back to the
59				// global count" is handled implicitly by holding state; we intentionally
60				// do not clear `loaded` so the badge keeps rendering.
61			}
62		}
63	
64		$effect(() => {
65			const pid = projectId;
66			if (!pid) {
67				loaded = false;
68				return;
69			}
70			void refresh(pid);
71			const h = setInterval(() => void refresh(pid), 3000);
72			return () => clearInterval(h);
73		});
74	</script>
75	
76	{#if projectId && workersHref}
77		<a
78			data-testid="drain-indicator"
79			data-state={active ? 'active' : 'idle'}
80			href={workersHref}
81			class="flex items-center gap-1.5 rounded border border-gray-200 px-2 py-1 text-xs font-medium text-gray-700 hover:bg-gray-100 dark:border-gray-700 dark:text-gray-200 dark:hover:bg-gray-800"
82			aria-label="Drain queue status"
83			title="Click for worker overview"
84		>
85			{#if active}
86				<Loader2 class="h-3.5 w-3.5 animate-spin text-blue-600 dark:text-blue-400" />
87			{:else}
88				<span class="inline-block h-2 w-2 rounded-full bg-gray-400 dark:bg-gray-500"></span>
89			{/if}
90			<span>{label || 'Queue: …'}</span>
91		</a>
92	{/if}
